- [ ] Handle turns blue on hover
- [ ] Drag UP = chat gets TALLER
- [ ] Drag DOWN = chat gets SHORTER
- [ ] Min height 100px enforced
- [ ] Max height 60% enforced
- [ ] Viewport resizes as chat resizes

